/** Lookup by DANE code */
export const MUNICIPIO_BY_CODE = new Map(MUNICIPIOS.map(m => [m.code, m]));

/** Only municipalities with CHIP data available */
export const MUNICIPIOS_CON_CHIP = MUNICIPIOS.filter(m => m.chipCode !== '');

/** Unique departments */
export const DEPARTAMENTOS = [...new Set(MUNICIPIOS.map(m => m.dept))].sort();

/** Search municipalities by name (case-insensitive) */
export function searchMunicipios(query: string, limit = 20): Municipio[] {
  const q = query.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  return MUNICIPIOS.filter(m => {
    const name = m.name.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    const dept = m.dept.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    return name.includes(q) || dept.includes(q) || m.code.includes(q);
  }).slice(0, limit);
}